import{_ as a,c as e,o as m,b as t}from"./app.fab5ca80.js";const k='{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 4","description":"","frontmatter":{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 4","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 2.","tags":"vim-2","date":"2021-02-07T00:00:00.000Z"},"headers":[],"relativePath":"texts/shiva-sutra-vimarshini/2/4.md"}',i={},p=t('<div class="stanza"><a href="#s2.4" id="s2.4" class="num">2.4</a><div class="sans"><p>\u092F\u0947\u0937\u093E\u0902 \u0924\u0941 \u090F\u0935\u0902\u0935\u093F\u0927\u092E\u0947\u0924\u0928\u094D\u092E\u0928\u094D\u0924\u094D\u0930\u0935\u0940\u0930\u094D\u092F\u0902 \u092A\u094D\u0930\u094B\u0915\u094D\u0924\u092E\u0939\u093E\u0939\u094D\u0930\u0926\u093E\u0928\u0941\u0938\u0928\u094D\u0927\u093E\u0928\u094C\u092A\u092F\u093F\u0915\u092E\u092A\u093F \u092A\u0930\u092E\u0947\u0936\u094D\u0935\u0930\u0947\u091A\u094D\u091B\u093E\u0924 \u090F\u0935 \u0928 \u0939\u0943\u0926\u092F\u0919\u094D\u0917\u092E\u0940\u092D\u0935\u0924\u094D\u092F\u092A\u093F \u0924\u094D\u0935\u093E\u0928\u0941\u0937\u0919\u094D\u0917\u093F\u0915\u092E\u093E\u0924\u094D\u0930\u0935\u093F\u0928\u094D\u0926\u0941\u0928\u093E\u0926\u093E\u0926\u093F\u0915\u0932\u093E\u091C\u0928\u093F\u0924\u093E\u0938\u0941 \u092E\u093F\u0924\u0938\u093F\u0926\u094D\u0927\u093F\u0937\u0941 \u091A\u093F\u0924\u094D\u0924\u0902 \u0930\u094B\u0939\u0924\u093F \u0924\u0947\u0937\u093E\u092E\u094D\u2014</p><blockquote><p><strong>\u0917\u0930\u094D\u092D\u0947 \u091A\u093F\u0924\u094D\u0924\u0935\u093F\u0915\u093E\u0938\u094B\u093D\u0935\u093F\u0936\u093F\u0937\u094D\u091F\u0935\u093F\u0926\u094D\u092F\u093E\u0938\u094D\u0935\u092A\u094D\u0928\u0903\u0965\u096A\u0965</strong></p></blockquote><p>\u0917\u0930\u094D\u092D\u094B\u093D\u0916\u094D\u092F\u093E\u0924\u093F\u0930\u094D\u092E\u0939\u093E\u092E\u093E\u092F\u093E \u0924\u0924\u094D\u0930 \u0924\u0926\u093E\u0924\u094D\u092E\u0915\u0947 \u092E\u093F\u0924\u092E\u0928\u094D\u0924\u094D\u0930\u0938\u093F\u0926\u094D\u0927\u093F\u092A\u094D\u0930\u092A\u091E\u094D\u091A\u0947 \u092F\u0936\u094D\u091A\u093F\u0924\u094D\u0924\u0938\u094D\u092F \u0935\u093F\u0915\u093E\u0938\u0938\u094D\u0924\u093E\u0935\u0928\u094D\u092E\u093E\u0924\u094D\u0930\u0947 \u092A\u094D\u0930\u092A\u091E\u094D\u091A\u0947 \u0938\u0928\u094D\u0924\u094B\u0937\u094B\u093D\u0938\u093E\u0935\u0947\u0935\u093E\u0935\u093F\u0936\u093F\u0937\u094D\u091F\u093E \u0938\u0930\u094D\u0935\u091C\u0928\u0938\u093E\u0927\u093E\u0930\u0923\u0930\u0942\u092A\u093E \u0935\u093F\u0926\u094D\u092F\u093E \u0915\u093F\u091E\u094D\u091A\u093F\u091C\u094D\u091C\u094D\u091E\u0924\u094D\u0935\u0930\u0942\u092A\u093E\u0936\u0941\u0926\u094D\u0927\u0935\u093F\u0926\u094D\u092F\u093E \u0938\u0948\u0935 \u0938\u094D\u0935\u092A\u094D\u0928\u094B \u092D\u0947\u0926\u0928\u093F\u0937\u094D\u0920\u094B \u0935\u093F\u091A\u093F\u0924\u094D\u0930\u094B \u0935\u093F\u0915\u0932\u094D\u092A\u093E\u0924\u094D\u092E\u093E \u092D\u094D\u0930\u092E\u0903\u0964 \u0924\u0926\u0941\u0915\u094D\u0924\u0902 \u092A\u093E\u0924\u091E\u094D\u091C\u0932\u0947</p><blockquote><p>\u0924\u0947 \u0938\u092E\u093E\u0927\u093E\u0935\u0941\u092A\u0938\u0930\u094D\u0917\u093E \u0935\u094D\u092F\u0941\u0924\u094D\u0925\u093E\u0928\u0947 \u0938\u093F\u0926\u094D\u0927\u092F\u0903\u0965 (\u0969-\u0969\u096D)</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0924\u0926\u0947\u0924\u0924\u094D</p><blockquote><p>\u0905\u0924\u094B \u0935\u093F\u0928\u094D\u0926\u0941\u0930\u0924\u094B \u0928\u093E\u0926\u094B \u0930\u0942\u092A\u092E\u0938\u094D\u092E\u093E\u0926\u0924\u094B \u0930\u0938\u0903\u0964<br> \u092A\u094D\u0930\u0935\u0930\u094D\u0924\u0928\u094D\u0924\u0947\u093D\u091A\u093F\u0930\u0947\u0923\u0948\u0935 \u0915\u094D\u0937\u094B\u092D\u0915\u0924\u094D\u0935\u0947\u0928 \u0926\u0947\u0939\u093F\u0928\u0903\u0965</p></blockquote><p>\u0907\u0924\u094D\u092F\u0928\u0947\u0928 \u0926\u0930\u094D\u0936\u093F\u0924\u092E\u094D\u0965\u096A\u0965</p></div><hr><div class="trans"><p>Ye\u1E63\u0101\u1E41 tu eva\u1E41vidhametanmantrav\u012Brya\u1E41 proktamah\u0101hrad\u0101nusandh\u0101naupayikamapi parame\u015Bvarecch\u0101ta eva na h\u1E5Bdaya\u1E45gam\u012Bbhavatyapi tv\u0101nu\u1E63a\u1E45gikam\u0101travindun\u0101d\u0101dikal\u0101janit\u0101su mitasiddhi\u1E63u citta\u1E41 rohati te\u1E63\u0101m\u2014</p><blockquote><p><strong>Garbhe cittavik\u0101so&#39;vi\u015Bi\u1E63\u1E6Davidy\u0101svapna\u1E25||4||</strong></p></blockquote><p>Garbho&#39;khy\u0101tirmah\u0101m\u0101y\u0101 tatra tad\u0101tmake mitamantrasiddhiprapa\xF1ce ya\u015Bcittasya vik\u0101sast\u0101vanm\u0101tre prapa\xF1ce santo\u1E63o&#39;s\u0101vev\u0101vi\u015Bi\u1E63\u1E6D\u0101 sarvajanas\u0101dh\u0101ra\u1E47ar\u016Bp\u0101 vidy\u0101 ki\xF1cijj\xF1atvar\u016Bp\u0101\u015Buddhavidy\u0101 saiva svapno bhedani\u1E63\u1E6Dho vicitro vikalp\u0101tm\u0101 bhrama\u1E25| Tadukta\u1E41 p\u0101ta\xF1jale</p><blockquote><p>Te sam\u0101dh\u0101vupasarg\u0101 vyutth\u0101ne siddhaya\u1E25|| (3-37)</p></blockquote><p>iti| Tadetat</p><blockquote><p>Ato vindurato n\u0101do r\u016Bpamasm\u0101dato rasa\u1E25|<br> Pravartante&#39;cire\u1E47aiva k\u1E63obhakatvena dehina\u1E25||</p></blockquote><p>ityanena dar\u015Bitam||4||</p></div><hr><p>[\u0422\u043E, \u0447\u0442\u043E \u0432\u044B\u0440\u0430\u0436\u0435\u043D\u043E \u0432 \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u043C \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435 \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0441\u044F] \u043A \u0442\u0435\u043C <em>(te\u1E63\u0101m)</em>, \u043A\u043E\u0433\u043E <em>(ye\u1E63\u0101m)</em> \u0442\u0430\u043A\u0430\u044F <em>(eva\u1E41vidham)</em> \u0441\u0438\u043B\u0430 <em>(v\u012Bryam)</em> \u044D\u0442\u043E\u0439 <em>(etad)</em> \u043C\u0430\u043D\u0442\u0440\u044B <em>(mantra)</em>, [\u043A\u043E\u0442\u043E\u0440\u0430\u044F --\u0442.\u0435. \u0441\u0438\u043B\u0430-- \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0442\u0430\u043A\u0436\u0435 <em>(api)</em> \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C <em>(upayikam)</em> \u043E\u0431\u044A\u0435\u0434\u0438\u043D\u0435\u043D\u0438\u044F <em>(ca)</em> \u0441 \u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u044B\u043C <em>(prokta)</em> \u0412\u0435\u043B\u0438\u043A\u0438\u043C <em>(mah\u0101)</em> \u041E\u0437\u0435\u0440\u043E\u043C <em>(hrada)</em><sup>1</sup></p><p>, \u043D\u0435 <em>(na)</em> \u0437\u0430\u0442\u0440\u0430\u0433\u0438\u0432\u0430\u0435\u0442 [\u0438\u0445] \u0441\u0435\u0440\u0434\u0446\u0430 <em>(h\u1E5Bdaya\u1E45gam\u012B-bhavati)</em> \u0447\u0435\u0440\u0435\u0437 \u0412\u043E\u043B\u044E <em>(icch\u0101ta\u1E25)</em> \u0412\u044B\u0441\u0448\u0435\u0433\u043E <em>(parama)</em> \u0413\u043E\u0441\u043F\u043E\u0434\u0430 <em>(\u012B\u015Bvara eva)</em>, \u0438, \u043F\u043E\u0436\u0430\u043B\u0443\u0439 <em>(api tu)</em>, \u0447\u044C\u0438 <em>(ye\u1E63\u0101m)</em> \u0443\u043C\u044B <em>(cittam)</em> \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u044B \u043D\u0430 <em>(rohati)</em> \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0435 <em>(mita)</em> \u0441\u0432\u0435\u0440\u0445\u044A\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \u0441\u0438\u043B\u044B <em>(siddhi\u1E63u)</em>, \u0440\u043E\u0436\u0434\u0435\u043D\u043D\u044B\u0435 <em>(janit\u0101su)</em> \u015Aakti <em>(kal\u0101)</em>, [\u0442\u0430\u043A\u0438\u0435 \u043A\u0430\u043A] Vindu <em>(vindu)</em>, N\u0101da <em>(n\u0101da)</em>, \u0438 \u0442.\u043F. <em>(\u0101di)</em><sup>2</sup>, [\u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F] \u0442\u043E\u043B\u044C\u043A\u043E <em>(m\u0101tra)</em> \u0432\u0442\u043E\u0440\u0438\u0447\u043D\u044B\u043C\u0438 <em>(\u0101nu\u1E63a\u1E45gika)</em>\u2014</p><blockquote><p><strong>\u041C\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u043E\u0435 <em>(citta)</em> \u0443\u0434\u043E\u0432\u043B\u0435\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 <em>(vik\u0101sa\u1E25)</em> [\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u043C\u0438] \u043C\u0430\u0439\u0438\u0447\u0435\u0441\u043A\u0438\u043C\u0438 \u0441\u0438\u043B\u0430\u043C\u0438 <em>(garbhe)</em> [\u2014 \u044D\u0442\u043E \u0432\u0441\u0435\u0433\u043E \u043B\u0438\u0448\u044C] \u0441\u043E\u043D <em>(svapna\u1E25)</em>, [\u043E\u0441\u043D\u043E\u0432\u0430\u043D\u043D\u044B\u0439 \u043D\u0430] \u043D\u0438\u0437\u0448\u0435\u043C <em>(avi\u015Bi\u1E63\u1E6Da)</em> \u0437\u043D\u0430\u043D\u0438\u0438 <em>(vidy\u0101)</em>||4||</strong></p></blockquote><p>Garbha, \u0438\u043B\u0438 \u043C\u0430\u0439\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u0441\u0438\u043B\u044B <em>(garbha\u1E25)</em> [\u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F] \u0438\u0437\u043D\u0430\u0447\u0430\u043B\u044C\u043D\u044B\u043C \u043D\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u0435\u043C --\u043D\u0435\u0432\u0435\u0434\u0435\u043D\u0438\u0435\u043C \u043E \u0441\u0432\u043E\u0435\u043C \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C \u0418\u0441\u0442\u0438\u043D\u043D\u043E\u043C \u042F-- <em>(akhy\u0101ti\u1E25)</em>, [\u0442\u0430\u043A\u0436\u0435 \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E\u043C \u043A\u0430\u043A] \u0432\u0435\u043B\u0438\u043A\u0430\u044F <em>(mah\u0101)</em> \u041C\u0430\u0439\u044F <em>(m\u0101y\u0101)</em>. \u042D\u0442\u043E <em>(ya\u1E25)</em> \u043C\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u043E\u0435 <em>(cittasya)</em> \u0443\u0434\u043E\u0432\u043B\u0435\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 <em>(vik\u0101sa\u1E25)</em> \u0442\u0430\u043C <em>(tatra)</em>, \u0442.\u0435. \u0432 \u044D\u0442\u043E\u043C [Garbha] <em>(tad-\u0101tmake)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043C\u0430\u043D\u0438\u0444\u0435\u0441\u0442\u0430\u0446\u0438\u0435\u0439 <em>(prapa\xF1ce)</em> \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0445 <em>(mita)</em> \u0441\u0432\u0435\u0440\u0445\u044A\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 \u0441\u0438\u043B <em>(siddhi)</em>, \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u044F\u0449\u0438\u0445 \u0438\u0437 \u043C\u0430\u043D\u0442\u0440\u044B <em>(mantra)</em>, [\u0435\u0441\u0442\u044C] \u0443\u0434\u043E\u0432\u043B\u0435\u0442\u0432\u043E\u0440\u0435\u043D\u043D\u043E\u0441\u0442\u044C <em>(santo\u1E63a\u1E25)</em> [\u0442\u0430\u043A\u0438\u043C] \u043E\u0431\u0443\u0441\u043B\u043E\u0432\u043B\u0435\u043D\u043D\u044B\u043C <em>(t\u0101vat-m\u0101tre)</em> \u0444\u0435\u043D\u043E\u043C\u0435\u043D\u043E\u043C <em>(prapa\xF1ce)</em> --\u0442.\u0435. \u0444\u0435\u043D\u043E\u043C\u0435\u043D\u043E\u043C, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 \u0442\u043E\u043B\u044C\u043A\u043E \u0442\u0430\u043A\u043E\u0439 \u0441\u0442\u0435\u043F\u0435\u043D\u0438--. \u042D\u0442\u043E <em>(asau eva)</em> [\u0435\u0441\u0442\u044C] \u0437\u043D\u0430\u043D\u0438\u0435 <em>(vidy\u0101)</em>, \u043E\u0431\u0449\u0435\u0435 <em>(s\u0101dh\u0101ra\u1E47a-r\u016Bp\u0101)</em> \u0434\u043B\u044F \u0432\u0441\u0435\u0445 <em>(sarva)</em> \u043B\u044E\u0434\u0435\u0439 <em>(jana)</em>, [\u0438 \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E] \u043D\u0438\u0437\u0448\u0435\u0435, \u0438\u043B\u0438 \u043D\u0435\u0441\u043F\u0435\u0446\u0438\u0444\u0438\u0447\u0435\u0441\u043A\u043E\u0435 <em>(avi\u015Bi\u1E63\u1E6D\u0101)</em>. [\u042D\u0442\u043E] \u043D\u0435\u0447\u0438\u0441\u0442\u043E\u0435 <em>(a\u015Buddha)</em> \u0437\u043D\u0430\u043D\u0438\u0435 <em>(vidy\u0101)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0438\u043C\u0435\u0435\u0442 \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0435 \u043A \u043F\u043E\u043D\u0438\u043C\u0430\u043D\u0438\u044E <em>(j\xF1atva-r\u016Bp\u0101)</em> \u043B\u0438\u0448\u044C \u043D\u0435\u043C\u043D\u043E\u0433\u043E <em>(ki\xF1cid)</em>. \u042D\u0442\u043E <em>(s\u0101)</em> \u0431\u0435\u0437\u0443\u0441\u043B\u043E\u0432\u043D\u043E [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] <em>(eva)</em> \u0441\u043D\u043E\u043C \u0441\u043E \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u044F\u043C\u0438 <em>(svapna\u1E25)</em>, \u0442.\u0435. \u0441\u0442\u0440\u0430\u043D\u043D\u043E\u0439 <em>(vicitra\u1E25)</em> \u043F\u0443\u0442\u0430\u043D\u0438\u0446\u0435\u0439 <em>(bhrama\u1E25)</em>, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u0439 \u0438\u0437 \u043C\u044B\u0441\u043B\u0435\u0439 <em>(vikalpa-\u0101tm\u0101)</em> [\u0438] \u043E\u0441\u043D\u043E\u0432\u0430\u043D\u043D\u043E\u0439 <em>(ni\u1E63\u1E6Dha\u1E25)</em> \u043D\u0430 \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u044F\u0445 --\u0442.\u0435. \u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438-- <em>(bheda)</em>|</p><p>\u042D\u0442\u043E <em>(tad)</em> [\u0442\u0430\u043A\u0436\u0435] \u043F\u0440\u0438\u0437\u043D\u0430\u0435\u0442\u0441\u044F <em>(uktam)</em> \u0432 P\u0101ta\xF1jalayogas\u016Btra-s <em>(p\u0101ta\xF1jale)</em>:</p><blockquote><p>&quot;\u042D\u0442\u0438 [\u0441\u0432\u0435\u0440\u0445\u044A\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \u0441\u0438\u043B\u044B] <em>(te)</em> \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u043F\u0440\u0435\u043F\u044F\u0442\u0441\u0442\u0432\u0438\u044F\u043C\u0438, \u0438\u043B\u0438 \u043F\u043E\u043C\u0435\u0445\u0430\u043C\u0438 <em>(upasarg\u0101\u1E25)</em> \u0432 Sam\u0101dhi <em>(sam\u0101dhau)</em>, [\u043D\u043E] \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u044F\u043C\u0438 <em>(siddhaya\u1E25)</em> \u0432\u043E Vyutth\u0101na --\u0442.\u0435. \u0432 \u043E\u0431\u044B\u0447\u043D\u043E\u043C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u0443\u043C \u043A\u043E\u043B\u0435\u0431\u043B\u0435\u0442\u0441\u044F-- <em>(vyutth\u0101ne... iti)</em>&quot;||(III-37)</p></blockquote><p>\u0422\u0430 \u0436\u0435 \u0441\u0430\u043C\u0430\u044F [\u0438\u0441\u0442\u0438\u043D\u0430] <em>(tad etad)</em> \u0431\u044B\u043B\u0430 \u043F\u0440\u043E\u0434\u0435\u043C\u043E\u043D\u0441\u0442\u0440\u0438\u0440\u043E\u0432\u0430\u043D\u0430 <em>(dar\u015Bitam)</em> \u044D\u0442\u0438\u043C [\u0430\u0444\u043E\u0440\u0438\u0437\u043C\u043E\u043C \u0432 Spandak\u0101rik\u0101-s] <em>(anena)</em>:</p><blockquote><p>&quot;\u0418\u0437 \u044D\u0442\u043E\u0433\u043E [Unme\u1E63a] <em>(atas... atas... asm\u0101t atas)</em>, Vindu --\u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439 \u0441\u0432\u0435\u0442-- <em>(vindu\u1E25)</em>, N\u0101da --\u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439 \u0437\u0432\u0443\u043A-- <em>(n\u0101da\u1E25)</em>, R\u016Bpa --\u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F \u0444\u043E\u0440\u043C\u0430-- <em>(r\u016Bpam)</em> [\u0438] Rasa --\u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439 \u0432\u043A\u0443\u0441-- <em>(rasa\u1E25)</em> \u0432\u0441\u043A\u043E\u0440\u0435 <em>(acire\u1E47a eva)</em> \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F <em>(pravartante)</em> \u0432 \u0432\u043E\u043F\u043B\u043E\u0449\u0435\u043D\u043D\u043E\u0439 \u0434\u0443\u0448\u0435 <em>(dehina\u1E25)</em> \u043A\u0430\u043A \u0431\u0435\u0441\u043F\u043E\u043A\u043E\u044F\u0449\u0438\u0439 \u0444\u0430\u043A\u0442\u043E\u0440 <em>(k\u1E63obhakatvena... iti)</em>&quot;||<br> [\u0421\u043C. Spandak\u0101rik\u0101-s III, 10]</p></blockquote><p>||4||</p><hr><ol><li><p>\u0421\u043C\u043E\u0442\u0440\u0438\u0442\u0435 I, 22 \u0432 \u043A\u043E\u043D\u0446\u0435 \u041F\u0435\u0440\u0432\u043E\u0439 \u0413\u043B\u0430\u0432\u044B.</p></li><li><p>Vindu (\u0438\u043B\u0438 Bindu) \u0438 N\u0101da \u0432 \u0434\u0430\u043D\u043D\u043E\u043C \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435 \u0438\u043D\u0442\u0435\u0440\u043F\u0440\u0435\u0442\u0438\u0440\u0443\u044E\u0442\u0441\u044F \u043A\u0430\u043A \u043D\u0435\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \u0441\u0432\u0435\u0440\u0445\u044A\u0435\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \u0441\u0432\u0435\u0442 \u0438 \u0437\u0432\u0443\u043A, \u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u043C\u044B\u0435 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0443\u044E\u0449\u0438\u043C \u0432\u043E \u0432\u0440\u0435\u043C\u044F \u0435\u0433\u043E \u0434\u0443\u0445\u043E\u0432\u043D\u043E\u0439 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0438, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0432 \u043A\u043E\u043D\u0435\u0447\u043D\u043E\u043C \u0438\u0442\u043E\u0433\u0435 \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u043E\u0442\u0432\u043B\u0435\u043A\u0430\u044E\u0449\u0438\u043C \u0444\u0430\u043A\u0442\u043E\u0440\u043E\u043C. \u041A\u043E\u043D\u0435\u0447\u043D\u043E, \u0430\u0432\u0442\u043E\u0440 \u0433\u043E\u0432\u043E\u0440\u0438\u0442 \u043D\u0435 \u043E \u0412\u044B\u0441\u0448\u0438\u0445 Vindu \u0438 N\u0101da, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u043F\u0430\u0440\u043E\u0439 \u015Aakti \u0438 \u015Aiva.</p></li></ol></div>',1),r=[p];function s(d,o,n,v,u,h){return m(),e("div",null,r)}var l=a(i,[["render",s]]);export{k as __pageData,l as default};
